    74→export const parseDate = (value: string): Date | null => {
    75→  // Remove a formatação
    76→  const numbers = value.replace(/\D/g, "");
    77→
    78→  if (numbers.length !== 8) {
    79→    return null;
    80→  }
    81→
    82→  const day = parseInt(numbers.substring(0, 2), 10);
    83→  const month = parseInt(numbers.substring(2, 4), 10);
    84→  const year = parseInt(numbers.substring(4, 8), 10);
    85→
    86→  // Validação básica
    87→  if (
    88→    day < 1 ||
    89→    day > 31 ||
    90→    month < 1 ||
    91→    month > 12 ||
    92→    year < 1900 ||
    93→    year > new Date().getFullYear()
    94→  ) {
    95→    return null;
    96→  }
    97→
    98→  // Cria a data (mês é 0-indexed no JavaScript)
    99→  const date = new Date(year, month - 1, day);
   100→
   101→  // Verifica se a data é válida
   102→  if (
   103→    date.getDate() !== day ||
   104→    date.getMonth() !== month - 1 ||
   105→    date.getFullYear() !== year
   106→  ) {
   107→    return null;
   108→  }
   109→
   110→  return date;
   111→};
