   124→export const createBrazilDate = (
   125→  year: number,
   126→  month: number,
   127→  day: number,
   128→  hour: number = 0,
   129→  minute: number = 0
   130→): Date => {
   131→  // Create date in local timezone but adjusted for Brazil
