   136→export const formatToBrazilISO = (date: Date): string => {
   137→  // Get the current timezone offset and Brazil timezone offset difference
   138→  const currentOffset = date.getTimezoneOffset(); // in minutes
   139→  const brazilOffsetMinutes = BRAZIL_TIMEZONE_OFFSET * 60; // Convert to minutes
   140→
   141→  // Adjust the date to Brazil timezone
   142→  const adjustedDate = new Date(
   143→    date.getTime() + (currentOffset + brazilOffsetMinutes) * 60000
   144→  );
   145→
   146→  // Format as ISO string but replace Z with Brazil offset
   147→  const isoString = adjustedDate.toISOString();
   148→  return isoString.replace("Z", "-03:00");
   149→};
   150→
   151→export const parseFromBrazilISO = (isoString: string): Date => {
   152→  // If the string already has timezone info, use it directly
   153→  if (
   154→    isoString.includes("T") &&
   155→    (isoString.includes("Z") ||
   156→      isoString.includes("+") ||
   157→      isoString.includes("-"))
   158→  ) {
   159→    return new Date(isoString);
   160→  }
   161→
   162→  // If it's just a date string, treat it as Brazil local time
   163→  const date = new Date(isoString);
   164→  return date;
   165→};
