   205→/**
   206→ * Formata uma data usando o timezone do usuário
   207→ * @param date - Data a ser formatada (Date object ou string ISO)
   208→ * @param formatPattern - Padrão de formatação (padrão: dd/MM/yyyy)
   209→ * @returns String com a data formatada no timezone do usuário
   210→ */
   211→export const formatDateByTz = (
   212→  date: Date | string,
   213→  formatPattern: string = "dd/MM/yyyy"
   214→): string => {
   215→  const dateObj = typeof date === "string" ? new Date(date) : date;
   216→
   217→  // Extrai componentes da data em UTC para evitar timezone shifts
   218→  const [year, month, day] = dateObj.toISOString().split("T")[0].split("-");
   219→
   220→  // Cria nova data sem timezone offset
   221→  const normalizedDate = new Date(Number(year), Number(month) - 1, Number(day));
   222→
   223→  // Obtém o timezone do usuário
   224→  const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
   225→
   226→  return formatInTimeZone(normalizedDate, timeZone, formatPattern, {
   227→    locale: ptBR,
   228→  });
   229→};
