   231→/**
   232→ * Formata um horário em UTC (dados já estão em UTC)
   233→ * @param date - Data/hora a ser formatada (Date object ou string ISO)
   234→ * @param formatPattern - Padrão de formatação (padrão: HH:mm)
   235→ * @returns String com o horário formatado em UTC
   236→ */
   237→export const formatTimeByTz = (
   238→  date: Date | string,
   239→  formatPattern: string = "HH:mm"
   240→): string => {
   241→  const dateObj = typeof date === "string" ? new Date(date) : date;
   242→
   243→  // Extrair horas e minutos diretamente do UTC (dados já estão em UTC)
   244→  const hours = dateObj.getUTCHours().toString().padStart(2, '0');
   245→  const minutes = dateObj.getUTCMinutes().toString().padStart(2, '0');
   246→
   247→  // Suporta apenas formato HH:mm por enquanto
   248→  if (formatPattern === "HH:mm") {
   249→    return `${hours}:${minutes}`;
   250→  }
   251→
   252→  // Fallback para outros formatos (pode ser expandido se necessário)
   253→  return `${hours}:${minutes}`;
   254→};
